  ('elementary-64311456-moex-00895', 'elementary-64311456', 'elementary-64311456-moex-110-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '依據身心障礙者權益保障法，身心障礙者在身體系統構造或功能，有損傷或不全導致顯著偏離或喪失， 影響其活動與參與社會生活，可分為幾大類？', '["八大類", "十大類", "十二大類", "十六大類"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "df7cdcc487d5", "answer_pdf_sha1": "df191591992f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00896', 'elementary-64311456', 'elementary-64311456-moex-110-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '依據身心障礙者權益保障法的規定，身心障礙者於遭到遺棄，且情況危急非立即給予保護、安置或其他 處置，其生命、身體或自由有立即之危險或有危險之虞者，直轄市、縣（市）主管機關應予緊急保護、 安置或為其他必要之處置；上述之緊急保護安置，若未經過法院裁定，不得超過多久時間？', '["二十四小時", "三十六小時", "四十八小時", "七十二小時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "df7cdcc487d5", "answer_pdf_sha1": "df191591992f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00897', 'elementary-64311456', 'elementary-64311456-moex-110-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '有關身心障礙者權益保障法之規定，對於支持服務的敘述，下列何者正確？', '["未提供對號座之大眾運輸工具應設置供身心障礙者及老弱婦孺優先乘坐之博愛座，其比率不低於總座 位數百分之十", "公共停車場應保留百分之三停車位，作為行動不便之身心障礙者專用停車位", "身心障礙者搭乘國內大眾運輸工具，憑身心障礙證明，應予免費優待", "身心障礙者進入收費之公營或公設民營風景區、康樂場所或文教設施，憑身心障礙證明應予免費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "df7cdcc487d5", "answer_pdf_sha1": "df191591992f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00898', 'elementary-64311456', 'elementary-64311456-moex-110-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '下列何類人員在執行職務時知悉老人有疑似疏忽、虐待、遺棄等情事，致有生命、身體、健康或自由之 危難之情況者，沒有通報當地直轄市、縣（市）主管機關之責任？', '["司法人員", "老人的鄰居", "村（里）幹事", "老人住院時的主治醫師"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "df7cdcc487d5", "answer_pdf_sha1": "df191591992f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00899', 'elementary-64311456', 'elementary-64311456-moex-110-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '依據全民健康保險法，全民健康保險的保險財務，應由保險人至少每幾年精算一次？', '["兩年", "三年", "五年", "十年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "df7cdcc487d5", "answer_pdf_sha1": "df191591992f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00900', 'elementary-64311456', 'elementary-64311456-moex-110-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '依據兒童及少年性剝削防制條例之規定，經法院認定有安置必要者，應裁定安置於直轄市、縣（市）主 管機關自行設立或委託之兒童及少年福利機構、寄養家庭、中途學校或其他適當之醫療、教育機構，期 間不得逾多少年？', '["一年", "二年", "三年", "四年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "df7cdcc487d5", "answer_pdf_sha1": "df191591992f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00901', 'elementary-64311456', 'elementary-64311456-moex-110-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '依據兒童及少年福利與權益保障法之規定，直轄市、縣（市）政府，應建立整合性服務機制，辦理兒童 及少年福利措施。其中對於無力撫育其未滿幾歲之子女或受監護人者，視需要予以托育、家庭生活扶助 或醫療補助？', '["三歲", "六歲", "十二歲", "十八歲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "df7cdcc487d5", "answer_pdf_sha1": "df191591992f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00902', 'elementary-64311456', 'elementary-64311456-moex-110-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '依據身心障礙者權益保障法之規定，身心障礙證明有效期限最長為多少年？', '["五年", "六年", "十年", "十五年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "df7cdcc487d5", "answer_pdf_sha1": "df191591992f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00903', 'elementary-64311456', 'elementary-64311456-moex-110-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '依家庭暴力防治法之規定，法院依法准許家庭暴力加害人會面交往其未成年子女時，應審酌子女及被害 人之安全，並得為下列一款或數款命令。下列有關命令之敘述何者錯誤？', '["經法院同意，可過夜會面交往", "負擔監督會面交往費用", "於特定安全場所交付子女", "準時、安全交還子女，並繳納保證金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "df7cdcc487d5", "answer_pdf_sha1": "df191591992f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
